#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()
required = ["package.json", "app", "components"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

(ROOT / "app/page.tsx").write_text('import { MatchCard } from "@/components/MatchCard";\nimport { StandingCard } from "@/components/StandingCard";\nimport { formatStartsIn, resultLabel } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getNextMatch, getStandings } from "@/lib/scoring";\nimport type { Match, MatchResult } from "@/lib/types";\n\nexport const revalidate = 600;\n\nfunction leaderText(standings: ReturnType<typeof getStandings>, played: number): string {\n  if (played === 0) return "Todos empiezan igual";\n  const top = standings[0]?.points ?? 0;\n  const tied = standings.filter((row) => row.points === top).length;\n  return tied > 1 ? "Empate en cabeza" : "Líder provisional";\n}\n\nfunction heroStatus(match: Match, result?: MatchResult): string {\n  if (result?.status === "FINISHED") return resultLabel(result);\n  if (result?.status === "LIVE") return result.minute ? `En juego · ${result.minute}\'` : "En juego";\n\n  const countdown = formatStartsIn(match.date, match.timeEt);\n  return countdown === "En juego" ? "Pendiente de marcador" : countdown;\n}\n\nconst podiumMedals = ["🥇", "🥈", "🥉"];\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n  const nextMatch = getNextMatch(payload.results);\n  const podium = standings.slice(0, 3);\n  const rest = standings.slice(3);\n\n  return (\n    <section className="screen">\n      <header className="app-header hero-sport compact-hero">\n        <div>\n          <h1>🏆 Mundial 2026</h1>\n          {nextMatch ? (\n            <div className="hero-next">\n              <div>{nextMatch.home} - {nextMatch.away}</div>\n              <span>{heroStatus(nextMatch, payload.results[nextMatch.id])}</span>\n            </div>\n          ) : (\n            <p>{played}/{total} partidos puntuados</p>\n          )}\n        </div>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">Actualizando resultados...</div>\n      ) : null}\n\n      {nextMatch ? (\n        <section className="block compact-next-block">\n          <div className="block-heading">\n            <h2>Próximo partido</h2>\n            <span>{played}/{total} puntuados</span>\n          </div>\n          <MatchCard match={nextMatch} result={payload.results[nextMatch.id]} featured />\n        </section>\n      ) : null}\n\n      <section className="block classification-block">\n        <div className="block-heading">\n          <h2>Clasificación</h2>\n          <span>1 punto por acertar</span>\n        </div>\n\n        <div className="leader-note">{leaderText(standings, played)}</div>\n\n        <div className="podium">\n          {podium.map((row, index) => (\n            <a key={row.player} href={`/pronosticos/${encodeURIComponent(row.player)}`} className={`podium-card rank-${index + 1}`}>\n              <div className="podium-top">{podiumMedals[index]}</div>\n              <div className="podium-name">{row.player}</div>\n              <div className="podium-score">{row.points}</div>\n              <div className="muted">{row.played === 0 ? "Salida" : `${row.correct}/${row.played} · ${row.percentage}%`}</div>\n            </a>\n          ))}\n        </div>\n\n        <div className="standing-list">\n          {rest.map((row, index) => (\n            <StandingCard key={row.player} row={row} position={index + 4} compact />\n          ))}\n        </div>\n      </section>\n    </section>\n  );\n}\n', encoding="utf-8")

css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")
marker = "/* Compact home polish */"
if marker not in css:
    css_path.write_text(css.rstrip() + "\n\n" + '/* Compact home polish */\n.compact-hero {\n  margin-top: 0;\n  margin-bottom: 28px;\n  padding: 0 26px;\n  border: 0;\n  background: transparent;\n  box-shadow: none;\n}\n\n.compact-hero h1 {\n  font-size: clamp(42px, 10.5vw, 60px);\n  line-height: 0.95;\n  margin-bottom: 18px;\n  letter-spacing: -0.055em;\n}\n\n.compact-hero .hero-next {\n  max-width: 86%;\n  padding: 18px 22px;\n  border: 1px solid rgba(20, 16, 9, 0.09);\n  border-radius: 26px;\n  background: rgba(255, 255, 255, 0.82);\n  box-shadow: 0 14px 34px rgba(62, 43, 11, 0.07);\n}\n\n.compact-hero .hero-next div {\n  font-size: clamp(26px, 7vw, 38px);\n  line-height: 1.02;\n}\n\n.compact-hero .hero-next span {\n  margin-top: 6px;\n  display: block;\n  color: #c66c00;\n  font-size: clamp(18px, 5vw, 26px);\n  font-weight: 800;\n}\n\n.compact-next-block {\n  margin-top: 0;\n}\n\n.compact-next-block .block-heading,\n.classification-block .block-heading {\n  margin-bottom: 12px;\n}\n\n.compact-next-block .match-card {\n  padding: 16px;\n  border-radius: 24px;\n}\n\n.compact-next-block .match-topline {\n  margin-bottom: 18px;\n}\n\n.compact-next-block .match-main {\n  margin-bottom: 12px;\n}\n\n.compact-next-block .team {\n  font-size: clamp(24px, 6vw, 34px);\n}\n\n.compact-next-block .score {\n  min-width: 54px;\n  min-height: 48px;\n  padding: 8px 12px;\n}\n\n.compact-next-block .match-time {\n  margin-bottom: 14px;\n  font-size: 15px;\n}\n\n.compact-next-block .pick-row {\n  gap: 8px;\n}\n\n.compact-next-block .pick-button {\n  min-height: 44px;\n  padding: 10px 14px;\n  border-radius: 18px;\n}\n\n.classification-block {\n  margin-top: 24px;\n}\n\n.leader-note {\n  margin-bottom: 10px;\n}\n\n@media (max-width: 390px) {\n  .compact-hero {\n    padding: 0 18px;\n    margin-bottom: 22px;\n  }\n\n  .compact-hero h1 {\n    font-size: 42px;\n  }\n\n  .compact-hero .hero-next {\n    max-width: 92%;\n    padding: 16px 18px;\n  }\n\n  .compact-next-block .match-card {\n    padding: 14px;\n  }\n\n  .compact-next-block .team {\n    font-size: 24px;\n  }\n\n  .compact-next-block .match-time {\n    font-size: 14px;\n  }\n}\n' + "\n", encoding="utf-8")

print("Pulido compacto aplicado:")
print("- Cabecera más pequeña.")
print("- Eliminado bloque Todo listo.")
print("- Próximo partido más compacto.")
print("- Clasificación sube en la home.")
print("- En juego solo si la API confirma partido en directo; si no, Pendiente de marcador.")
print("")
print("Ejecuta:")
print("npm run build")
print("git add .")
print("git commit -m 'Compact home polish'")
print("git push")
print("npx vercel --prod")
